def create_process(pid, name, priority=0):
    """Create a process represented as a dictionary."""
    return {
        "pid": pid,
        "name": name,
        "priority": priority,
        "status": "ready"
    }


def schedule_processes(processes):
    """Sort processes by priority (highest first), then by pid for ties."""
    return sorted(processes, key=lambda p: (-p["priority"], p["pid"]))


def change_status(process, new_status):
    """Update the status of a process."""
    process["status"] = new_status
    return process


def process_summary(processes):
    """Count processes in each status category."""
    summary = {"ready": 0, "running": 0, "blocked": 0}
    for p in processes:
        status = p["status"]
        if status in summary:
            summary[status] += 1
    return summary


# Test the process manager
p1 = create_process(1, "Browser", priority=3)
p2 = create_process(2, "Editor", priority=5)
p3 = create_process(3, "Terminal", priority=3)

scheduled = schedule_processes([p1, p2, p3])
for p in scheduled:
    print(f"PID {p['pid']}: {p['name']} (priority {p['priority']})")

p1 = change_status(p1, "running")
p3 = change_status(p3, "blocked")

print(process_summary([p1, p2, p3]))

